VkDevice device = VK_NULL_HANDLE;
VkDeferredOperationKHR deferredOperation = VK_NULL_HANDLE;
uint32_t infoCount = 0;
VkAccelerationStructureBuildGeometryInfoKHR infos = {};
infos.sType = VK_STRUCTURE_TYPE_ACCELERATION_STRUCTURE_BUILD_GEOMETRY_INFO_KHR;
VkAccelerationStructureBuildRangeInfoKHR* * ppBuildRangeInfos = nullptr;

VkResult result = vkBuildAccelerationStructuresKHR(
    device,
    deferredOperation,
    infoCount,
    &infos,
    ppBuildRangeInfos
);

if (result == VK_SUCCESS) {
